using System;
using UnityEngine;

/// <summary>
/// Forma da zona de detecção de um inimigo (Enemy Creator — Etapa 1.4).
///
/// - Circular: círculo de raio "range" ao redor do inimigo.
/// - ConeFrontal: cone de "range" de distância e "coneAngle" graus, centrado
///   na direcção para onde o inimigo está virado.
/// - LinhaRecta: linha de "range" de comprimento e "width" de largura, na
///   direcção para onde o inimigo está virado (ou nas duas direcções, se
///   "onlyIfFacingPlayer" estiver desligado).
/// - AreaRectangular: caixa de "range" × "width".
/// - TriggerOnly: sem geometria própria — detecta apenas via um Collider2D
///   (trigger) neste GameObject (OnTriggerEnter2D/Exit2D).
/// - AttacksFirst: sem fase de detecção — o alvo é sempre o player e o
///   inimigo vai directo para "Perseguindo" (a lógica de ataque, Etapa 2.1,
///   decide quando atacar com base no alcance do próprio ataque).
/// </summary>
public enum DetectionShape
{
    Circular,
    ConeFrontal,
    LinhaRecta,
    AreaRectangular,
    TriggerOnly,
    AttacksFirst
}

/// <summary>
/// Como decidir se este inimigo detecta um player furtivo (Etapa 8.1).
/// </summary>
public enum StealthDetectionMode
{
    /// <summary>Deriva de EnemyData: detecta furtivos quando "weaknesses.canBeIgnoredByStealth" está DESLIGADO (fonte de verdade única).</summary>
    Auto,

    /// <summary>Override manual: detecta sempre furtivos, ignorando o EnemyData.</summary>
    SempreDetecta,

    /// <summary>Override manual: nunca detecta furtivos, ignorando o EnemyData.</summary>
    NuncaDetecta
}

/// <summary>
/// Detecção do player por um inimigo (Enemy Creator — Etapa 1.4). Define
/// <see cref="EnemyController.Target"/> e conduz as transições de estado
/// Idle/Patrulhando/VoltandoParaCasa → Alerta → Perseguindo → (volta a)
/// VoltandoParaCasa quando o alvo é perdido.
///
/// Dispara <see cref="OnPlayerSuspicious"/> (ícone "?"), <see cref="OnPlayerSpotted"/>
/// (ícone "!") e <see cref="OnPlayerLost"/> para EnemyFeedback (Etapa 7.1)
/// mostrar os ícones/efeitos correspondentes.
///
/// Não altera o estado durante PreparandoAtaque/Atacando/Recuperando/Atordoado
/// — esses estados são geridos por EnemyAttack/EnemyHealth (Etapas 2.1/1.3).
/// </summary>
[RequireComponent(typeof(EnemyController))]
public class EnemyDetection : MonoBehaviour
{
    [Header("Forma de Detecção")]
    public DetectionShape shape = DetectionShape.Circular;

    [Header("Alcance / Geometria")]
    [Tooltip("Raio (Circular) ou distância máxima (ConeFrontal/LinhaRecta/AreaRectangular). Ignorado em TriggerOnly/AttacksFirst.")]
    public float range = 5f;

    [Tooltip("Ângulo total do cone, em graus (ConeFrontal apenas).")]
    [Range(1f, 360f)]
    public float coneAngle = 90f;

    [Tooltip("Largura da área/linha, perpendicular à direcção do inimigo (LinhaRecta/AreaRectangular).")]
    public float width = 1f;

    [Header("Linha de Visão")]
    [Tooltip("Se activo, a detecção falha se houver algo destas camadas entre o inimigo e o player (ex: paredes). Se desligado, detecta através de paredes (sensor).")]
    public bool requiresLineOfSight = false;

    [Tooltip("Camadas que bloqueiam a linha de visão.")]
    public LayerMask lineOfSightBlockers;

    [Header("Orientação")]
    [Tooltip("Restringe a detecção ao lado para onde o inimigo está virado. Para ConeFrontal isto já é o comportamento natural; para Circular/LinhaRecta/AreaRectangular limita a zona a um semicírculo/lado frontal.")]
    public bool onlyIfFacingPlayer = false;

    [Header("Tempos")]
    [Tooltip("Tempo (segundos) em Alerta a confirmar o alvo antes de passar a Perseguindo. 0 = confirma imediatamente (sem fase de Alerta).")]
    public float timeToNotice = 0.4f;

    [Tooltip("Tempo (segundos) sem detectar o alvo antes de o perder (o inimigo volta para casa).")]
    public float timeToLoseTarget = 2f;

    [Header("Detecção Especial")]
    [Tooltip("Detecção de furtivos (Etapa 8.1): Auto = deriva de EnemyData.weaknesses.canBeIgnoredByStealth (fonte de verdade única); SempreDetecta/NuncaDetecta = override manual desta instância.")]
    public StealthDetectionMode stealthDetection = StealthDetectionMode.Auto;

    [Tooltip("Detecta o player mesmo que esteja submerso (ver WaterDetector.IsSubmerged).")]
    public bool canDetectSubmerged = false;

    [Tooltip("Detecta o player mesmo que esteja na categoria Voador (ex: torretas anti-aéreas).")]
    public bool canDetectFlying = true;

    [Header("Sensor de Proximidade Adicional")]
    [Tooltip("Detecta sempre o player dentro deste raio, ignorando forma/ângulo/linha-de-visão/orientação (mas não as imunidades furtivo/submerso/voador acima). 0 = desligado.")]
    public float proximityRadius = 0f;

    [Header("Visual (auto-detectado se vazio)")]
    [SerializeField] private SpriteRenderer spriteRenderer;
    [Tooltip("Desliga se, com flipX = false, o sprite olha por defeito para a esquerda.")]
    public bool spriteFacesRightByDefault = true;

    /// <summary>Disparado ao entrar em Alerta (ícone "?").</summary>
    public event Action OnPlayerSuspicious;

    /// <summary>Disparado ao confirmar o alvo e passar a Perseguindo (ícone "!").</summary>
    public event Action OnPlayerSpotted;

    /// <summary>Disparado ao perder o alvo (timeToLoseTarget esgotado).</summary>
    public event Action OnPlayerLost;

    private EnemyController _controller;
    private float _noticeTimer;
    private float _loseTimer;

    /// <summary>Estado do Collider2D (trigger) deste GameObject — usado por TriggerOnly/AttacksFirst.</summary>
    private bool _triggerHasPlayer;

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();

        if (spriteRenderer == null)
            spriteRenderer = _controller.SpriteRenderer;
    }

    private void Update()
    {
        if (_controller.IsTerminal) return;

        var player = _controller.Player;
        if (player == null) return;

        if (shape == DetectionShape.AttacksFirst)
        {
            _controller.Target = player;

            if (_controller.State == EnemyState.Idle || _controller.State == EnemyState.Patrulhando)
                _controller.SetState(EnemyState.Perseguindo);

            return;
        }

        bool detected = IsPlayerDetected(player);

        switch (_controller.State)
        {
            case EnemyState.Idle:
            case EnemyState.Patrulhando:
            case EnemyState.VoltandoParaCasa:
                if (detected) HandleNewDetection(player);
                break;

            case EnemyState.Alerta:
                if (detected)
                {
                    _noticeTimer += Time.deltaTime;
                    if (_noticeTimer >= timeToNotice) ConfirmTarget();
                }
                else
                {
                    TickLoseTimer();
                }
                break;

            case EnemyState.Perseguindo:
                if (detected) _loseTimer = 0f;
                else TickLoseTimer();
                break;

            default:
                // PreparandoAtaque/Atacando/Recuperando/Atordoado: geridos por
                // EnemyAttack/EnemyHealth. Só evita perder o alvo enquanto isso decorre.
                if (detected) _loseTimer = 0f;
                break;
        }
    }

    private void HandleNewDetection(Transform player)
    {
        _controller.Target = player;
        _noticeTimer = 0f;
        _loseTimer = 0f;

        if (timeToNotice <= 0f)
        {
            ConfirmTarget();
        }
        else
        {
            _controller.SetState(EnemyState.Alerta);
            OnPlayerSuspicious?.Invoke();
        }
    }

    private void ConfirmTarget()
    {
        _controller.SetState(EnemyState.Perseguindo);
        OnPlayerSpotted?.Invoke();
    }

    private void TickLoseTimer()
    {
        _loseTimer += Time.deltaTime;
        if (_loseTimer < timeToLoseTarget) return;

        _controller.Target = null;

        if (_controller.State == EnemyState.Perseguindo || _controller.State == EnemyState.Alerta)
            _controller.SetState(EnemyState.VoltandoParaCasa);

        OnPlayerLost?.Invoke();
    }

    private bool IsPlayerDetected(Transform player)
    {
        if (!CanDetectThisTarget(player)) return false;

        if (shape == DetectionShape.TriggerOnly) return _triggerHasPlayer;

        if (proximityRadius > 0f)
        {
            float distSqr = ((Vector2)player.position - (Vector2)transform.position).sqrMagnitude;
            if (distSqr <= proximityRadius * proximityRadius) return true;
        }

        return ShapeContainsPlayer(player);
    }

    /// <summary>
    /// True se este inimigo detecta players furtivos (Etapa 8.1): em Auto,
    /// deriva de !EnemyData.weaknesses.canBeIgnoredByStealth; senão usa o
    /// override manual (SempreDetecta/NuncaDetecta).
    /// </summary>
    public bool CanDetectStealthy
    {
        get
        {
            switch (stealthDetection)
            {
                case StealthDetectionMode.SempreDetecta: return true;
                case StealthDetectionMode.NuncaDetecta: return false;
                default:
                    var weaknesses = _controller != null && _controller.Data != null ? _controller.Data.weaknesses : null;
                    return weaknesses != null && !weaknesses.canBeIgnoredByStealth;
            }
        }
    }

    /// <summary>Filtros de imunidade: furtivo/camuflado/submerso/voador (ver AnimalCategory, CamoAbility e WaterDetector).</summary>
    private bool CanDetectThisTarget(Transform player)
    {
        if (!CanDetectStealthy && HasCategory(player, AnimalCategory.Furtivo)) return false;

        // Camuflagem activa (CamoAbility — P5): conta como Furtivo temporário.
        if (!CanDetectStealthy && IsCamoActive(player)) return false;

        // Pó Dourado (Tarefa "Itens Consumíveis"): invisibilidade temporária — mesmo tratamento que Furtivo/Camuflagem.
        if (!CanDetectStealthy && IsInvisible(player)) return false;
        if (!canDetectFlying && HasCategory(player, AnimalCategory.Voador)) return false;
        if (!canDetectSubmerged && IsSubmerged(player)) return false;

        return true;
    }

    private bool HasCategory(Transform player, AnimalCategory category)
    {
        var fs = player.GetComponent<FormSwitcher>();
        if (fs == null || fs.CurrentForm == null) return false;

        return (fs.CurrentForm.categories & category) != 0;
    }

    private bool IsSubmerged(Transform player)
    {
        var wd = player.GetComponent<WaterDetector>();
        return wd != null && wd.IsSubmerged;
    }

    private bool IsCamoActive(Transform player)
    {
        var camo = player.GetComponent<CamoAbility>();
        return camo != null && camo.IsCamoActive;
    }

    /// <summary>Pó Dourado (Tarefa "Itens Consumíveis"): true enquanto a invisibilidade temporária do player estiver activa.</summary>
    private bool IsInvisible(Transform player)
    {
        var consumable = player.GetComponent<PlayerConsumableEffects>();
        return consumable != null && consumable.IsInvisible;
    }

    private bool ShapeContainsPlayer(Transform player)
    {
        Vector2 origin = transform.position;
        Vector2 toPlayer = (Vector2)player.position - origin;
        float dist = toPlayer.magnitude;
        Vector2 facing = FacingDirection();

        switch (shape)
        {
            case DetectionShape.Circular:
                if (dist > range) return false;
                if (onlyIfFacingPlayer && Vector2.Dot(facing, toPlayer) < 0f) return false;
                break;

            case DetectionShape.ConeFrontal:
                if (dist > range) return false;
                if (Vector2.Angle(facing, toPlayer) > coneAngle * 0.5f) return false;
                break;

            case DetectionShape.LinhaRecta:
            {
                if (Mathf.Abs(toPlayer.y) > width * 0.5f) return false;

                float forward = toPlayer.x * Mathf.Sign(facing.x == 0f ? 1f : facing.x);
                if (onlyIfFacingPlayer)
                {
                    if (forward < 0f || forward > range) return false;
                }
                else
                {
                    if (Mathf.Abs(toPlayer.x) > range) return false;
                }
                break;
            }

            case DetectionShape.AreaRectangular:
            {
                if (Mathf.Abs(toPlayer.y) > width * 0.5f) return false;

                float forward = toPlayer.x * Mathf.Sign(facing.x == 0f ? 1f : facing.x);
                if (onlyIfFacingPlayer)
                {
                    if (forward < 0f || forward > range) return false;
                }
                else
                {
                    if (Mathf.Abs(toPlayer.x) > range) return false;
                }
                break;
            }
        }

        if (requiresLineOfSight && !HasLineOfSight(player)) return false;

        return true;
    }

    private bool HasLineOfSight(Transform player)
    {
        if (lineOfSightBlockers.value == 0) return true;

        var hit = Physics2D.Linecast(transform.position, player.position, lineOfSightBlockers);
        return hit.collider == null;
    }

    /// <summary>Direcção para onde o inimigo está virado (com base no flipX do SpriteRenderer).</summary>
    private Vector2 FacingDirection()
    {
        if (spriteRenderer == null) return Vector2.right;

        bool facingRight = spriteFacesRightByDefault ? !spriteRenderer.flipX : spriteRenderer.flipX;
        return facingRight ? Vector2.right : Vector2.left;
    }

    /// <summary>
    /// Usado por TriggerOnly/AttacksFirst: requer um Collider2D (isTrigger = true)
    /// neste GameObject (ou filho com este componente) que englobe a zona de detecção.
    /// </summary>
    private void OnTriggerEnter2D(Collider2D other)
    {
        if (shape != DetectionShape.TriggerOnly && shape != DetectionShape.AttacksFirst) return;
        if (_controller.Player == null || other.transform != _controller.Player) return;

        _triggerHasPlayer = true;
    }

    private void OnTriggerExit2D(Collider2D other)
    {
        if (shape != DetectionShape.TriggerOnly && shape != DetectionShape.AttacksFirst) return;
        if (_controller.Player == null || other.transform != _controller.Player) return;

        _triggerHasPlayer = false;
    }

    private void OnDrawGizmosSelected()
    {
        if (shape == DetectionShape.TriggerOnly || shape == DetectionShape.AttacksFirst) return;

        var sr = spriteRenderer != null ? spriteRenderer : GetComponent<SpriteRenderer>();
        bool facingRight = sr == null || (spriteFacesRightByDefault ? !sr.flipX : sr.flipX);
        Vector2 facing = facingRight ? Vector2.right : Vector2.left;

        Gizmos.color = new Color(1f, 0.4f, 0f, 0.6f);
        Vector3 origin = transform.position;

        switch (shape)
        {
            case DetectionShape.Circular:
                Gizmos.DrawWireSphere(origin, range);
                break;

            case DetectionShape.ConeFrontal:
            {
                Vector2 left = RotateDegrees(facing, coneAngle * 0.5f);
                Vector2 right = RotateDegrees(facing, -coneAngle * 0.5f);
                Gizmos.DrawLine(origin, origin + (Vector3)(left * range));
                Gizmos.DrawLine(origin, origin + (Vector3)(right * range));
                Gizmos.DrawLine(origin + (Vector3)(left * range), origin + (Vector3)(right * range));
                break;
            }

            case DetectionShape.LinhaRecta:
            case DetectionShape.AreaRectangular:
            {
                float fx = facing.x >= 0f ? 1f : -1f;
                float minX = onlyIfFacingPlayer ? 0f : -range;
                float maxX = range;
                Vector3 a = origin + new Vector3(minX * fx, width * 0.5f, 0f);
                Vector3 b = origin + new Vector3(maxX * fx, width * 0.5f, 0f);
                Vector3 c = origin + new Vector3(maxX * fx, -width * 0.5f, 0f);
                Vector3 d = origin + new Vector3(minX * fx, -width * 0.5f, 0f);
                Gizmos.DrawLine(a, b);
                Gizmos.DrawLine(b, c);
                Gizmos.DrawLine(c, d);
                Gizmos.DrawLine(d, a);
                break;
            }
        }

        if (proximityRadius > 0f)
        {
            Gizmos.color = new Color(1f, 1f, 0f, 0.6f);
            Gizmos.DrawWireSphere(origin, proximityRadius);
        }
    }

    private static Vector2 RotateDegrees(Vector2 v, float degrees)
    {
        float rad = degrees * Mathf.Deg2Rad;
        float cos = Mathf.Cos(rad);
        float sin = Mathf.Sin(rad);
        return new Vector2(v.x * cos - v.y * sin, v.x * sin + v.y * cos);
    }
}
